"use strict";parserFactory.register("timotxt.com",()=>new TimotxtParser);class TimotxtParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=t.baseURI+"dir",r=(await HttpClient.fetchHtml(e)).responseXML.querySelector("ul.all");return util.hyperlinksToChapterList(r)}findContent(t){return t.querySelector(".chapter-content")}extractTitleImpl(t){return t.querySelector("h1")}extractAuthor(t){return t.querySelector("#detail span.author")?.textContent??super.extractAuthor(t)}findCoverImageUrl(t){return util.getFirstImgSrc(t,"#detail")}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll(".intro")]}}